# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Prevent insecure universal link handling.
# Category: insecure_universal_links

import UIKit
import SwiftUI

// MARK: - Universal Link Handler
class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedSchemes = ["https"]
    private let passwordResetPath = "/reset-password"
    
    private init() {}
    
    func handleUniversalLink(_ userActivity: NSUserActivity) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return handleURL(url)
    }
    
    func handleURL(_ url: URL) -> Bool {
        guard validateURL(url) else {
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        
        if components.path == passwordResetPath {
            return handlePasswordReset(components: components)
        }
        
        return false
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            return false
        }
        
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return false
        }
        
        return true
    }
    
    private func handlePasswordReset(components: URLComponents) -> Bool {
        guard let queryItems = components.queryItems,
              let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return false
        }
        
        guard validateToken(token) else {
            return false
        }
        
        DispatchQueue.main.async {
            self.navigateToPasswordReset(token: token)
        }
        
        return true
    }
    
    private func validateToken(_ token: String) -> Bool {
        let allowedCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        let tokenCharacterSet = CharacterSet(charactersIn: token)
        
        guard allowedCharacters.isSuperset(of: tokenCharacterSet) else {
            return false
        }
        
        guard token.count >= 20 && token.count <= 256 else {
            return false
        }
        
        return true
    }
    
    private func navigateToPasswordReset(token: String) {
        NotificationCenter.default.post(
            name: .navigateToPasswordReset,
            object: nil,
            userInfo: ["token": token]
        )
    }
}

