// MARK: - Password Reset View Model
class PasswordResetViewModel: ObservableObject {
    @Published var token: String = ""
    @Published var newPassword: String = ""
    @Published var confirmPassword: String = ""
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    
    func resetPassword() {
        guard validatePasswords() else { return }
        
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        let sanitizedToken = sanitizeToken(token)
        
        Task {
            do {
                try await performPasswordReset(token: sanitizedToken, newPassword: newPassword)
                await MainActor.run {
                    self.successMessage = "Password reset successfully"
                    self.isLoading = false
                }
            } catch {
                await MainActor.run {
                    self.errorMessage = error.localizedDescription
                    self.isLoading = false
                }
            }
        }
    }
    
    private func validatePasswords() -> Bool {
        guard !newPassword.isEmpty else {
            errorMessage = "Password cannot be empty"
            return false
        }
        
        guard newPassword.count >= 8 else {
            errorMessage = "Password must be at least 8 characters"
            return false
        }
        
        guard newPassword == confirmPassword else {
            errorMessage = "Passwords do not match"
            return false
        }
        
        return true
    }
    
    private func sanitizeToken(_ token: String) -> String {
        let allowedCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        return token.unicodeScalars
            .filter { allowedCharacters.contains($0) }
            .map { String($0) }
            .joined()
    }
    
    private func performPasswordReset(token: String, newPassword: String) async throws {
        guard let url = URL(string: "https://myapp.com/api/reset-password") else {
            throw URLError(.badURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: String] = [
            "token": token,
            "newPassword": newPassword
        ]
        
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        
        let (data, response) = try await URLSession.shared.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw URLError(.badServerResponse)
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            if let errorResponse = try? JSONDecoder().decode(ErrorResponse.self, from: data) {
                throw NSError(domain: "", code: httpResponse.statusCode, userInfo: [NSLocalizedDescriptionKey: errorResponse.message])
            }
            throw URLError(.badServerResponse)
        }
    }
}

struct ErrorResponse: Codable {
    let message: String
}

